mapper.update:
INSERT INTO TB_POP (
    POP_CD, POP_NM, POP_CNTS, POP_WIDTH, POP_HGT
  , POP_X_LOC, POP_Y_LOC, OPEN_START_DT, OPEN_END_DT
  , USE_YN, MENU_SYS_DIV, DEL_YN
  , CRE_USR_CD, CRE_DTM, UPD_USR_CD, UPD_DTM
) VALUES (
    #{popCd}, #{popNm}, #{popCnts}, #{popWidth}, #{popHgt}
  , #{popXLoc}, #{popYLoc}, #{openStartDt}, #{openEndDt}
  , #{useYn}, #{menuSysDiv}, 'N'
  , #{ssnUsrCd}, SYSDATE(), #{ssnUsrCd}, SYSDATE()
)
ON DUPLICATE KEY UPDATE
    POP_NM        = #{popNm}
  , POP_CNTS      = #{popCnts}
  , POP_WIDTH     = #{popWidth}
  , POP_HGT       = #{popHgt}
  , POP_X_LOC     = #{popXLoc}
  , POP_Y_LOC     = #{popYLoc}
  , OPEN_START_DT = #{openStartDt}
  , OPEN_END_DT   = #{openEndDt}
  , USE_YN        = #{useYn}
  , MENU_SYS_DIV  = #{menuSysDiv}
  , UPD_USR_CD    = #{ssnUsrCd}
  , UPD_DTM       = SYSDATE()
